from meutils.apis.oneapi.tasks import get_tasks

base_url = 'delay'


async def create(api_key: Optional[str] = None, task_ids: Optional[list] = None):
    task_ids = task_ids or await get_tasks(
        platform="",
        channel_id="21496",
        status="UNFINISHED",
        return_ids=True,
        end_timestamp=int(time.time())
    )
    # for task_id in task_ids:
    #     if remote_task_id := await redis_aclient.get(f"remote:{task_id}"):
    #         remote_task_id = remote_task_id.decode()
    #         if not remote_task_id.startswith("cgt-"):
    #             await redis_aclient.delete(f"remote:{task_id}")

    task_ids = [
                   task_id for task_id in task_ids
                   if task_id.startswith("delay::")
                      and not await redis_aclient.get(f"remote:{task_id}")
                      and not await redis_aclient.get(f"response:{task_id}")
               ][::-1]

    logger.debug(f"任务数量: {len(task_ids)}")

    if not api_key: return task_ids

    async def func(task_id):
        if (request := await redis_aclient.get(f"request:{task_id}")):
            request = SoraVideoRequest.model_validate_json(request)

            # 创建任务
            # if any(i in str(e) for i in ["NotLogin", "QuotaExceeded"]):
            try:
                video = await videos_nx.Tasks(api_key).create(request)
                await redis_aclient.set(f"remote:{task_id}", video.id, ex=7 * 24 * 3600)
                logger.debug("###############")

            except Exception as e:
                if any(i in str(e) for i in ["BLOCK", "ReqTextExistRisk"]):
                    logger.debug(e)
                    video = Video(id=task_id, status="failed")
                    await redis_aclient.set(f"response:{task_id}", video.model_dump_json(exclude_none=True), ex=3600)

                else:
                    return task_id

    return await asyncio.gather(*map(func, task_ids))

