async def get(task_ids, api_key: Optional[str] = None):
    task_ids = task_ids or await get_tasks(
        platform="",
        channel_id="21496",
        status="UNFINISHED",
        return_ids=True,
        end_timestamp=int(time.time())
    )

    task_ids = [task_id for task_id in task_ids if task_id.startswith("delay::")]
    for task_id in task_ids:
        if remote_task_id := await redis_aclient.get(f"remote:{task_id}"):
            remote_task_id = remote_task_id.decode()
            if not await redis_aclient.get(f"response:{task_id}"):

                video = await videos_nx.Tasks(api_key).get(remote_task_id)
                # logger.debug(video)
                if video.status in ["completed", "failed"]:  # 监听 写入 redis
                    await redis_aclient.set(
                        f"response:{task_id}",
                        video.model_dump_json(exclude_none=True),
                        ex=7 * 24 * 3600
                    )
                    logger.debug(f"任务已完成: {video}")
    # else:
    #     video = Video(id=task_id, status="failed")
    #     await redis_aclient.set(f"response:{task_id}", video.model_dump_json(exclude_none=True), ex=3600)


